import React from 'react';
import {
  Box,
  Grid,
  Card,
  CardContent,
  Typography,
  Button,
  Avatar,
  Chip,
  useTheme,
} from '@mui/material';
import {
  Timeline,
  Business,
  Verified,
  TrendingUp,
  Security,
} from '@mui/icons-material';
import { motion } from 'framer-motion';

const features = [
  {
    icon: <Timeline />,
    title: 'Theo dõi chuỗi cung ứng',
    description: 'Theo dõi toàn bộ quá trình từ sản xuất đến tiêu thụ',
  },
  {
    icon: <Business />,
    title: 'Quản lý doanh nghiệp',
    description: 'Quản lý thông tin và hoạt động của doanh nghiệp',
  },
  {
    icon: <Verified />,
    title: 'Xác thực sản phẩm',
    description: 'Xác thực nguồn gốc và chất lượng sản phẩm',
  },
  {
    icon: <Security />,
    title: 'Bảo mật thông tin',
    description: 'Đảm bảo an toàn và bảo mật thông tin',
  },
];

const stats = [
  { label: 'Doanh nghiệp', value: '1000+' },
  { label: 'Sản phẩm', value: '5000+' },
  { label: 'Người dùng', value: '10000+' },
  { label: 'Giao dịch', value: '50000+' },
];

const Home: React.FC = () => {
  const theme = useTheme();

  return (
    <Box>
      {/* Hero Section */}
      <Box
        sx={{
          bgcolor: 'primary.main',
          color: 'white',
          py: 8,
          borderRadius: 4,
          mb: 4,
          position: 'relative',
          overflow: 'hidden',
        }}
      >
        <Box
          sx={{
            position: 'absolute',
            top: 0,
            right: 0,
            bottom: 0,
            left: 0,
            background: 'linear-gradient(45deg, #2e7d32 30%, #1b5e20 90%)',
            opacity: 0.1,
          }}
        />
        <Grid container spacing={4} alignItems="center">
          <Grid item xs={12} md={6}>
            <motion.div
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.5 }}
            >
              <Typography variant="h2" gutterBottom>
                Giải pháp truy xuất nguồn gốc thực phẩm
              </Typography>
              <Typography variant="h5" sx={{ mb: 4 }}>
                Đảm bảo minh bạch và tin cậy trong chuỗi cung ứng thực phẩm
              </Typography>
              <Button
                variant="contained"
                size="large"
                sx={{
                  bgcolor: 'white',
                  color: 'primary.main',
                  '&:hover': {
                    bgcolor: 'grey.100',
                  },
                }}
              >
                Bắt đầu ngay
              </Button>
            </motion.div>
          </Grid>
          <Grid item xs={12} md={6}>
            <motion.div
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 0.5 }}
            >
              <Box
                component="img"
                src="/hero-image.png"
                alt="Hero"
                sx={{
                  width: '100%',
                  height: 'auto',
                  borderRadius: 2,
                }}
              />
            </motion.div>
          </Grid>
        </Grid>
      </Box>

      {/* Stats Section */}
      <Grid container spacing={4} sx={{ mb: 6 }}>
        {stats.map((stat, index) => (
          <Grid item xs={6} md={3} key={index}>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
            >
              <Card
                sx={{
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  p: 3,
                }}
              >
                <Typography variant="h3" color="primary" gutterBottom>
                  {stat.value}
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  {stat.label}
                </Typography>
              </Card>
            </motion.div>
          </Grid>
        ))}
      </Grid>

      {/* Features Section */}
      <Typography variant="h4" align="center" gutterBottom>
        Tính năng nổi bật
      </Typography>
      <Grid container spacing={4} sx={{ mb: 6 }}>
        {features.map((feature, index) => (
          <Grid item xs={12} sm={6} md={3} key={index}>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
            >
              <Card
                sx={{
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  p: 3,
                }}
              >
                <Avatar
                  sx={{
                    bgcolor: 'primary.main',
                    width: 56,
                    height: 56,
                    mb: 2,
                  }}
                >
                  {feature.icon}
                </Avatar>
                <Typography variant="h6" gutterBottom>
                  {feature.title}
                </Typography>
                <Typography
                  variant="body2"
                  color="text.secondary"
                  align="center"
                >
                  {feature.description}
                </Typography>
              </Card>
            </motion.div>
          </Grid>
        ))}
      </Grid>

      {/* CTA Section */}
      <Box
        sx={{
          bgcolor: 'grey.100',
          borderRadius: 4,
          p: 6,
          textAlign: 'center',
        }}
      >
        <Typography variant="h4" gutterBottom>
          Sẵn sàng tham gia?
        </Typography>
        <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
          Đăng ký ngay để trải nghiệm các tính năng tuyệt vời của chúng tôi
        </Typography>
        <Button
          variant="contained"
          size="large"
          sx={{
            bgcolor: 'primary.main',
            '&:hover': {
              bgcolor: 'primary.dark',
            },
          }}
        >
          Đăng ký miễn phí
        </Button>
      </Box>
    </Box>
  );
};

export default Home;
